import React, { useState } from "react";

const ContactPage: React.FC = () => {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: ""
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    // For now, simply alert the user. Later integrate with an API.
    alert("Thank you! Your message has been sent.");
  };

  return (
    <div
      className="container"
      style={{
        maxWidth: "700px",
        margin: "auto",
        padding: "40px 0",
        fontFamily: "Georgia, serif",
        color: "#000"
      }}
    >
      <h2 style={{ textAlign: "center", fontSize: "2rem", marginBottom: "20px" }}>
        Contact Us
      </h2>
      <p style={{ textAlign: "center", fontFamily: "Times New Roman, serif", fontSize: "1rem", marginBottom: "40px" }}>
        We’d love to hear from you. Please fill out the form below to get in touch.
      </p>
      <form onSubmit={handleSubmit}>
        <div className="mb-3">
          <label style={{ fontWeight: "bold" }}>Name</label>
          <input
            type="text"
            name="name"
            className="form-control"
            placeholder="Your Name"
            onChange={handleChange}
            required
            style={{ fontFamily: "Georgia, serif" }}
          />
        </div>
        <div className="mb-3">
          <label style={{ fontWeight: "bold" }}>Email</label>
          <input
            type="email"
            name="email"
            className="form-control"
            placeholder="Your Email"
            onChange={handleChange}
            required
            style={{ fontFamily: "Georgia, serif" }}
          />
        </div>
        <div className="mb-3">
          <label style={{ fontWeight: "bold" }}>Subject</label>
          <input
            type="text"
            name="subject"
            className="form-control"
            placeholder="Subject"
            onChange={handleChange}
            required
            style={{ fontFamily: "Georgia, serif" }}
          />
        </div>
        <div className="mb-3">
          <label style={{ fontWeight: "bold" }}>Message</label>
          <textarea
            name="message"
            className="form-control"
            rows={5}
            placeholder="Your Message"
            onChange={handleChange}
            required
            style={{ fontFamily: "Georgia, serif" }}
          ></textarea>
        </div>
        <div className="text-center">
          <button
            type="submit"
            className="btn btn-dark"
            style={{ fontFamily: "Georgia, serif", padding: "10px 30px" }}
          >
            Send Message
          </button>
        </div>
      </form>
    </div>
  );
};

export default ContactPage;
